import{_ as r,o as t,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const l=JSON.parse('{"title":"41. Accrued Days Off","description":"","frontmatter":{"title":"41. Accrued Days Off","eba":"Biomedical Engineers 2025-2028","topics":["hours","rosters","employment"]},"headers":[],"relativePath":"ebas/biomedical-engineers/hours-of-work/41-accrued-days-off.md","filePath":"ebas/biomedical-engineers/hours-of-work/41-accrued-days-off.md"}'),s={name:"ebas/biomedical-engineers/hours-of-work/41-accrued-days-off.md"};function n(c,e,i,d,f,u){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_41-accrued-days-off" tabindex="-1">41. Accrued Days Off <a class="header-anchor" href="#_41-accrued-days-off" aria-label="Permalink to &quot;41. Accrued Days Off&quot;">​</a></h1><p><strong>41.1</strong> A full time Employee rostered to work on shifts of eight hours duration will work 152 hours in each four week roster cycle to be worked as 19 days each of eight hours with an accrued day off (ADO) in each four week roster cycle.</p><p><strong>41.2</strong> Deferment of ADOs</p><p><strong>(a)</strong> Either the Employer or the Employee may request that the ADO not be taken in the four week roster cycle, and the other party must not unreasonably refuse to agree to the request.</p><p><strong>(b)</strong> Where an ADO is deferred in accordance with subclause 41.2(a) no more than 2 ADOs can be deferred at any one time unless otherwise agreed between the Employee and Employer.</p><p><strong>(c)</strong> Upon termination of employment, any untaken ADOs must be taken within the notice period prescribed by subclause 23.1. If this is not practicable, the Employee will be paid the untaken ADOs at the Employee’s ordinary time rate of pay.</p>',6)])])}const p=r(s,[["render",n]]);export{l as __pageData,p as default};
